import test from 'node:test';
import assert from 'node:assert/strict';
import { solveSchedule } from '../scheduler/solver.js';
import { defaultTimeSlots } from '../scheduler/time.js';
function data() { return { students: [], grades: [{ id: 'g1', name: 'G1', memberGradeIds: ['g1'], studentIds: [] }, { id: 'g2', name: 'G2', memberGradeIds: ['g2'], studentIds: [] }], cohorts: [{ id: 'c1', name: 'G1', gradeIds: ['g1'], studentIds: [] }, { id: 'c2', name: 'G2', gradeIds: ['g2'], studentIds: [] }, { id: 'c12', name: 'G1+G2', gradeIds: ['g1', 'g2'], studentIds: [] }], teachers: [{ id: 't1', name: 'T1', aliases: [], unavailableSlots: [], preferredSlots: [] }, { id: 't2', name: 'T2', aliases: [], unavailableSlots: [], preferredSlots: [] }], subjects: [{ id: 'math', name: '수학', aliases: [] }, { id: 'pe', name: '체육', aliases: [] }], rooms: [{ id: 'r1', name: 'R1' }], timeSlots: defaultTimeSlots(), warnings: [], errors: [], sourceSheets: [], constraints: [], diagnostics: { sheetRanges: {}, headers: [], gradeBlocks: [], teacherBlocks: [], skippedBlocks: [], detectedSubjectCount: 2, detectedRequirementCount: 2, allocationTeacherAliases: [], needsMapping: [] }, requirements: [{ id: 'r_math', subjectId: 'math', gradeIds: ['g1'], cohortIds: ['c1'], teacherIds: ['t1'], totalPeriodsPerWeek: 3, meetingsPerWeek: 3, meetingLengths: [1, 1, 1], roomId: 'r1', fixedSlots: [], allowedSlots: [], forbiddenSlots: [], preferredSlots: [], consecutive: false, afterSchool: false, sharedClass: false, eventType: 'normal-class', priority: 10 }, { id: 'r_pe', subjectId: 'pe', gradeIds: ['g1', 'g2'], cohortIds: ['c12'], teacherIds: ['t2'], totalPeriodsPerWeek: 2, meetingsPerWeek: 1, meetingLengths: [2], fixedSlots: [], allowedSlots: [], forbiddenSlots: [], preferredSlots: [], consecutive: true, afterSchool: false, sharedClass: true, eventType: 'shared-class', priority: 20 }] }; }
test('solver prevents teacher/grade/room conflicts and supports consecutive shared class', () => { const d = data(); const r = solveSchedule(d, { maxNodes: 5000, maxSeconds: 2, seed: 1, allowUnassigned: false, weights: {} }); assert.equal(r.unassigned.length, 0); const occupied = new Set(); for (const a of r.assignments) {
    for (let i = 0; i < a.length; i++) {
        for (const g of a.gradeIds) {
            const key = `g:${g}:${a.slot}:${i}`;
            assert(!occupied.has(key));
            occupied.add(key);
        }
        for (const t of a.teacherIds) {
            const key = `t:${t}:${a.slot}:${i}`;
            assert(!occupied.has(key));
            occupied.add(key);
        }
    }
} assert(r.assignments.some(a => a.length === 2 && a.gradeIds.length === 2)); });
test('impossible schedules are diagnosed as unassigned', () => { const d = data(); d.requirements[0].meetingLengths = Array(40).fill(1); d.requirements[0].totalPeriodsPerWeek = 40; const r = solveSchedule(d, { maxNodes: 1000, maxSeconds: 1, seed: 1, allowUnassigned: true, weights: {} }); assert(r.unassigned.length > 0); assert(r.issues.some(i => i.code === 'unassigned')); });
import { combineIssues, validateResult } from '../scheduler/validator.js';
function oneGradeReq(id, subjectId, teacherId, lengths, allowedSlots = [], priority = 1) { return { id, subjectId, gradeIds: ['g1'], cohortIds: ['c1'], teacherIds: [teacherId], totalPeriodsPerWeek: lengths.reduce((a, b) => a + b, 0), meetingsPerWeek: lengths.length, meetingLengths: lengths, roomId: undefined, fixedSlots: [], allowedSlots, forbiddenSlots: [], preferredSlots: [], consecutive: lengths.some(l => l > 1), afterSchool: false, sharedClass: false, eventType: 'normal-class', priority }; }
function tiny() { const d = data(); d.subjects = [{ id: 'a', name: 'A', aliases: [] }, { id: 'b', name: 'B', aliases: [] }, { id: 'c', name: 'C', aliases: [] }, { id: 'self', name: 'Self Study', aliases: [] }]; d.requirements = []; return d; }
test('partial leaves do not terminate search before a complete solution is found', () => { const d = tiny(); d.requirements = [oneGradeReq('blocked', 'a', 't1', [1], ['월-1']), oneGradeReq('occupier', 'b', 't1', [1], ['월-1', '월-2'])]; const r = solveSchedule(d, { maxNodes: 100, maxSeconds: 2, seed: 42, allowUnassigned: true, weights: {} }); assert.equal(r.unassigned.length, 0); assert.equal(r.progress.reason, 'complete'); assert.equal(r.assignments.length, 2); });
test('tiny node limit returns best partial with node-limit reason and period counts', () => { const d = tiny(); d.requirements = [oneGradeReq('a', 'a', 't1', [1]), oneGradeReq('b', 'b', 't2', [1]), oneGradeReq('c', 'c', 't2', [1])]; const r = solveSchedule(d, { maxNodes: 1, maxSeconds: 10, seed: 1, allowUnassigned: true, weights: {} }); assert.equal(r.progress.reason, 'node-limit'); assert.equal(r.progress.nodes, 1); assert.equal(r.progress.total, 3); assert.equal(r.progress.totalPeriods, 3); assert.equal(r.progress.assignedPeriods + r.progress.unassignedPeriods, 3); });
test('time limit can be triggered with injected clock', () => { const d = tiny(); d.requirements = [oneGradeReq('a', 'a', 't1', [1]), oneGradeReq('b', 'b', 't2', [1])]; let t = 0; const r = solveSchedule(d, { maxNodes: 1000, maxSeconds: 0.001, seed: 1, allowUnassigned: true, weights: {}, now: () => { t += 2; return t; } }); assert.equal(r.progress.reason, 'time-limit'); assert(r.progress.elapsedMs >= 2); });
test('objective prefers more assigned required periods before more instances', () => { const d = tiny(); d.requirements = [oneGradeReq('long', 'a', 't1', [3], ['월-1']), oneGradeReq('short1', 'b', 't2', [1], ['월-1']), oneGradeReq('short2', 'c', 't2', [1], ['월-2'])]; const r = solveSchedule(d, { maxNodes: 100, maxSeconds: 2, seed: 1, allowUnassigned: true, weights: {} }); assert(r.assignments.some(a => a.instanceId === 'long_1')); assert.equal(r.progress.assignedPeriods, 3); });
test('linked pair is assigned atomically and consecutively without math teacher on self study', () => { const d = tiny(); d.requirements = [{ ...oneGradeReq('math', 'a', 't1', [1], ['월-1']), linkedNextRequirementId: 'self' }, { ...oneGradeReq('self', 'self', 't1', [1], [], 1), teacherRule: { type: 'none' }, teacherIds: [], linkedPreviousRequirementId: 'math' }]; const r = solveSchedule(d, { maxNodes: 100, maxSeconds: 2, seed: 1, allowUnassigned: true, weights: {} }); assert.equal(r.unassigned.length, 0); const m = r.assignments.find(a => a.instanceId === 'math_1'); const s = r.assignments.find(a => a.instanceId === 'self_1'); assert.equal(m.slot, '월-1'); assert.equal(s.slot, '월-2'); assert.deepEqual(s.teacherIds, []); assert(s.studentIds.length === 0 || m.studentIds.every(st => s.studentIds.includes(st))); });
test('duplicate diagnostics are combined once', () => { const d = tiny(); d.requirements = [oneGradeReq('a', 'a', 't1', [40])]; const r = solveSchedule(d, { maxNodes: 100, maxSeconds: 1, seed: 1, allowUnassigned: true, weights: {} }); const combined = combineIssues(r.issues, validateResult(d, r), r.issues); assert.equal(combined.length, new Set(combined.map(i => `${i.level}|${i.code}|${i.message}`)).size); });
